class Solution:
    def numPairsDivisibleBy60(self, time):
        n = len(time)
        c = 0
        for i in range(n):
            for j in range(i + 1, n):
                if (time[i] + time[j]) % 60 == 0:
                    c += 1
        return c

solutions.python:
class Solution:
    def numPairsDivisibleBy60(self, time):
        counts = [0] * 60
        ans = 0
        for t in time:
            r = t % 60
            ans += counts[(60 - r) % 60]
            counts[r] += 1
        return ans

