var numPairsDivisibleBy60 = function(time) {
    const counts = new Array(60).fill(0);
    let ans = 0;
    for (const t of time) {
        const r = t % 60;
        ans += counts[(60 - r) % 60];
        counts[r] += 1;
    }
    return ans;
};
